package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Field;
import java.util.Map;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.apache.commons.csv.Lexer;
import org.apache.commons.csv.Assertions;
import org.apache.commons.csv.ExtendedBufferedReader;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVParserTest {

    private Reader mockReader;
    private CSVFormat mockFormat;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        mockFormat = mock(CSVFormat.class);
    }

    @Test
    void testConstructor_NullReader_ThrowsException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            new CSVParser(null, mockFormat);
        });
        assertEquals("reader", thrown.getMessage());
    }

    @Test
    void testConstructor_NullFormat_ThrowsException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            new CSVParser(mockReader, null);
        });
        assertEquals("format", thrown.getMessage());
    }

    @Test
    void testConstructor_ValidArguments_InitializesFields() throws Exception {
        // Since Mockito.mockStatic is not available, mock Assertions.notNull and ExtendedBufferedReader constructor differently.

        // Mock Assertions.notNull to do nothing using spy on Assertions class (static methods cannot be spied easily without mockStatic)
        // So we skip mocking Assertions.notNull, assuming it will not throw if arguments are not null.

        // Mock ExtendedBufferedReader constructor by using a spy subclass or by reflection to inject mocked BufferedReader into Lexer

        // Instead, create a subclass of ExtendedBufferedReader that we can mock
        ExtendedBufferedReader mockedBufferedReader = mock(ExtendedBufferedReader.class);

        // Mock the constructor of ExtendedBufferedReader by using a spy on CSVParser and override its lexer initialization via reflection

        // Create a spy CSVParser with mocks to bypass constructor calls that create ExtendedBufferedReader
        CSVParser parser = new CSVParser(mockReader, mockFormat);

        // Replace lexer field with a mocked Lexer created with mockedBufferedReader and mockFormat
        Lexer mockedLexer = mock(Lexer.class);
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(parser, mockedLexer);

        // Verify format field is set
        Field formatField = CSVParser.class.getDeclaredField("format");
        formatField.setAccessible(true);
        CSVFormat formatValue = (CSVFormat) formatField.get(parser);
        assertSame(mockFormat, formatValue);

        // Verify headerMap is initialized (not null)
        Field headerMapField = CSVParser.class.getDeclaredField("headerMap");
        headerMapField.setAccessible(true);
        Map<String, Integer> headerMap = (Map<String, Integer>) headerMapField.get(parser);
        assertNotNull(headerMap);

        // Verify lexer field is set to mockedLexer
        Lexer lexer = (Lexer) lexerField.get(parser);
        assertSame(mockedLexer, lexer);
    }
}
